Infraestrutura como codigo para database - EduPlatform Global - performance-tuning:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "ap-tokyo-1"
}

resource "oci_database_autonomous_database" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "database-security-066"

  # Configuracao especifica
  shape          = "BM.Standard.E5"

  tags = {
    project     = "EduPlatform Global - performance-tuning"
    environment = "security"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment security"
}

output "resource_id" {
  value = oci_database_autonomous_database.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "ap-tokyo-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=ocid1.database.us.a4257aa768519feab184f9bee79a891c"
terraform apply -var="compartment_ocid=ocid1.database.us.a4257aa768519feab184f9bee79a891c" -auto-approve
```

**Configuracao:**
- Compartment: `security`
- Region: `ap-tokyo-1`
- Shape: `BM.Standard.E5`
- OCPUs: `4`
- Storage: `50 GB`

Documentacao: https://registry.terraform.io/providers/oracle/oci/latest/docs

